using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, data structures, and the design of software and hardware systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Exploration of abstract structures, quantities, and patterns through rigorous proof and analysis." },
            new() { Id = 3, Code = "PHYS", Name = "Physics", Description = "Investigation of matter, energy, and the fundamental forces that govern the natural world." },
            new() { Id = 4, Code = "ENG", Name = "English", Description = "Critical reading, analytical writing, and the study of literature across cultures and periods." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Examination of past events, societies, and civilizations to understand the forces that shaped the modern world." },
            new() { Id = 6, Code = "BIO", Name = "Biology", Description = "Study of living organisms, their structure, function, evolution, and interactions with the environment." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 peer-reviewed papers and leads the university's AI Research Lab. She received her Ph.D. from MIT.", Email = "achen@university.edu", Office = "Engineering Hall 305" },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor of Computer Science", Bio = "Dr. Martinez focuses on distributed systems and cloud computing. He spent 10 years in industry at major tech companies before joining academia. He is passionate about bridging theory and practice.", Email = "rmartinez@university.edu", Office = "Engineering Hall 312" },
            new() { Id = 3, Name = "Dr. Sarah Kim", Title = "Professor of Mathematics", Bio = "Dr. Kim is an expert in combinatorics and graph theory. She has received multiple teaching excellence awards and is known for her engaging lecture style.", Email = "skim@university.edu", Office = "Science Building 201" },
            new() { Id = 4, Name = "Dr. James Wilson", Title = "Associate Professor of Mathematics", Bio = "Dr. Wilson researches applied mathematics with a focus on numerical methods and scientific computing. He collaborates extensively with the physics department.", Email = "jwilson@university.edu", Office = "Science Building 210" },
            new() { Id = 5, Name = "Dr. Emily Nakamura", Title = "Professor of Physics", Bio = "Dr. Nakamura is a theoretical physicist studying quantum mechanics and particle physics. She spent two years at CERN and regularly involves undergraduates in her research.", Email = "enakamura@university.edu", Office = "Physics Lab 102" },
            new() { Id = 6, Name = "Dr. Michael Brown", Title = "Associate Professor of Physics", Bio = "Dr. Brown specializes in astrophysics and cosmology. He manages the university observatory and leads popular public stargazing events each semester.", Email = "mbrown@university.edu", Office = "Physics Lab 115" },
            new() { Id = 7, Name = "Dr. Laura Thompson", Title = "Professor of English", Bio = "Dr. Thompson is a scholar of 19th-century American literature with a focus on transcendentalism. She has authored three books and frequently contributes to literary journals.", Email = "lthompson@university.edu", Office = "Humanities Hall 404" },
            new() { Id = 8, Name = "Dr. David Okafor", Title = "Associate Professor of History", Bio = "Dr. Okafor researches modern African history and post-colonial studies. He has conducted fieldwork across West Africa and brings a global perspective to his courses.", Email = "dokafor@university.edu", Office = "Humanities Hall 210" },
            new() { Id = 9, Name = "Dr. Patricia Reyes", Title = "Professor of Biology", Bio = "Dr. Reyes is a molecular biologist studying gene expression and epigenetics. Her lab has received continuous NIH funding for over a decade.", Email = "preyes@university.edu", Office = "Life Sciences 301" },
            new() { Id = 10, Name = "Dr. Thomas Anderson", Title = "Associate Professor of Biology", Bio = "Dr. Anderson focuses on ecology and conservation biology. He leads the university's field station and coordinates annual biodiversity surveys.", Email = "tanderson@university.edu", Office = "Life Sciences 215" },
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Description = "A broad introduction to computer science covering computational thinking, basic programming in Python, data representation, and an overview of major subfields. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Engineering Hall 100", DepartmentId = 1, InstructorId = 1, IsFeatured = true, MaxEnrollment = 120, CurrentEnrollment = 98 },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming, greedy algorithms). Includes weekly programming assignments in Java.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", Location = "Engineering Hall 110", DepartmentId = 1, InstructorId = 2, IsFeatured = false, MaxEnrollment = 60, CurrentEnrollment = 55 },
            new() { Id = 3, Code = "CS 350", Title = "Machine Learning", Description = "Foundations of machine learning including supervised and unsupervised learning, neural networks, and model evaluation. Students complete a semester-long project applying ML to a real-world dataset.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", Location = "Engineering Hall 205", DepartmentId = 1, InstructorId = 1, IsFeatured = true, MaxEnrollment = 40, CurrentEnrollment = 38 },
