@page "/courses"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService
@inject NavigationManager Navigation
@using Microsoft.AspNetCore.Components.Sections

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="search" value="@Search"
               placeholder="Search by title, code, or description" />
    </div>
    <div class="col-md-4">
        <label for="departmentId" class="form-label">Department</label>
        <select class="form-select" id="departmentId" name="departmentId">
            <option value="">All Departments</option>
            @foreach (var dept in CatalogService.GetAllDepartments())
            {
                @if (dept.Id == DepartmentId)
                {
                    <option value="@dept.Id" selected>@dept.Name</option>
                }
                else
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@{
    var courses = CatalogService.SearchCourses(Search, DepartmentId);
}

@if (DepartmentId.HasValue && DepartmentId.Value > 0)
{
    var dept = CatalogService.GetDepartmentById(DepartmentId.Value);
    if (dept is not null)
    {
        <div class="alert alert-info">
            Showing courses in <strong>@dept.Name</strong> (@dept.Code)
            — <a href="courses" class="alert-link">show all</a>
        </div>
    }
}

@if (courses.Count == 0)
{
    <div class="alert alert-warning">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted">Showing @courses.Count course(s)</p>

    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th>Enrollment</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td><strong>@course.Code</strong></td>
                        <td>@course.Title</td>
                        <td>@CatalogService.GetDepartmentName(course.DepartmentId)</td>
                        <td>@course.Credits</td>
                        <td>@course.Schedule</td>
                        <td>
                            @course.CurrentEnrollment / @course.MaxEnrollment
                            @if (course.CurrentEnrollment >= course.MaxEnrollment)
                            {
                                <span class="badge bg-danger ms-1">Full</span>
                            }
                        </td>
                        <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/courses/{id:int}"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course could not be found.</p>
    <a href="courses" class="btn btn-secondary">Back to Courses</a>
}
else
{
    <PageTitle>@course.Code — @course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="">Home</a></li>
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@course.Code — @course.Title</h1>
            <p class="lead">@course.Description</p>

            <h3 class="mt-4">Course Details</h3>
            <table class="table">
                <tbody>
                    <tr>
                        <th scope="row">Department</th>
                        <td>
                            @if (department is not null)
                            {
                                <a href="courses?departmentId=@department.Id">@department.Name</a>
                            }
                        </td>
                    </tr>
                    <tr>
                        <th scope="row">Credits</th>
                        <td>@course.Credits</td>
                    </tr>
                    <tr>
                        <th scope="row">Schedule</th>
                        <td>@course.Schedule</td>
                    </tr>
                    <tr>
                        <th scope="row">Location</th>
                        <td>@course.Location</td>
                    </tr>
                    <tr>
                        <th scope="row">Enrollment</th>
                        <td>
                            @course.CurrentEnrollment / @course.MaxEnrollment
                            @if (course.CurrentEnrollment >= course.MaxEnrollment)
                            {
                                <span class="badge bg-danger ms-2">Full</span>
                            }
                            else
                            {
                                <span class="badge bg-success ms-2">@(course.MaxEnrollment - course.CurrentEnrollment) seats available</span>
                            }
                        </td>
                    </tr>
                </tbody>
            </table>

            <div class="mt-3">
                <a href="enroll?courseId=@course.Id" class="btn btn-primary">Request Enrollment</a>
                <a href="courses" class="btn btn-outline-secondary ms-2">Back to Courses</a>
            </div>
        </div>

        <div class="col-lg-4 mt-4 mt-lg-0">
            @if (instructor is not null)
            {
                <div class="card">
                    <div class="card-header">
                        <h5 class="mb-0">Instructor</h5>
                    </div>
                    <div class="card-body">
                        <h5 class="card-title">@instructor.Name</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@instructor.Title</h6>
                        <p class="card-text">@instructor.Bio</p>
                        <ul class="list-unstyled">
                            <li><strong>Email:</strong> @instructor.Email</li>
                            <li><strong>Office:</strong> @instructor.Office</li>
                        </ul>
                    </div>
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private UniversityCourseCatalog.Models.Course? course;
    private UniversityCourseCatalog.Models.Department? department;
    private UniversityCourseCatalog.Models.Instructor? instructor;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourseById(Id);
        if (course is not null)
        {
            department = CatalogService.GetDepartmentById(course.DepartmentId);
            instructor = CatalogService.GetInstructorById(course.InstructorId);
        }
    }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Complete the form below to submit an enrollment request. You will receive a confirmation from the registrar's office.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.FullName</strong>. Your enrollment request for
            <strong>@(CatalogService.GetCourseById(Model.CourseId)?.Title ?? "the selected course")</strong>
            has been received.</p>
        <hr />
        <p class="mb-0">The registrar's office will review your request and notify you at <strong>@Model.Email</strong>.</p>
    </div>
    <a href="enroll" class="btn btn-primary">Submit Another Request</a>
}
else
{
    <div class="row">
        <div class="col-lg-8">
            <EditForm Model="Model" FormName="enrollment" OnValidSubmit="HandleSubmit" method="post">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="fullName" class="form-label">Full Name</label>
                    <InputText id="fullName" class="form-control" @bind-Value="Model.FullName" />
                    <ValidationMessage For="() => Model.FullName" class="text-danger" />
                </div>

